please help me !!!! this code generate me a xlsx corrupted file but i don't now why:

public withTables = async (matrix: any[][], cols: number, rows: number) => {
        try {
            let workbook = new Excel.Workbook();
            workbook = await workbook.xlsx.readFile('./template/import.xlsx');
            const worksheet = workbook.getWorksheet('Foglio1');
            const table = worksheet.getTable('Ciao');
            this.reference = (table as any).table.tableRef;
            const refArray: Array<string> = this.reference.split(':');
            const begin: string = refArray[0];
            if (begin.length > 2) {
                this.rowNum = parseInt(begin[1] + begin[2]);
            } else {
                this.rowNum = parseInt(begin[1]);
            }
            const finale: Array<any> = [];
            worksheet.getRow(this.rowNum).eachCell({includeEmpty: true}, (cell, colNumber) => {
                if (cell.value === null) {
                    finale.push(cell.value);
                }
            });
            for (let i = 1; i < matrix.length + 1; i++) {
                worksheet.insertRow(this.rowNum + i, finale.concat(matrix[i - 1]));
                console.log(this.rowNum);
            }
            return await workbook.xlsx.writeFile('export.xlsx');
        } catch (e) {
            console.log(e);
        }
    }
